// // This module implements a 16-bit wide parallel-in, parallel-out register that loads data on a falling clock edge and clears on a rising clock edge.
module top_module(out,in,ld,clk,clr);input [15:0] in;
    input ld,clk,clr;
    output reg [15:0] out;
    always@(posedge clk)
      if (clr)
        out <= 0;
    else if(ld)
        out <= in;endmodule
